package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.StringWriter;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithEscape() {
        // Given
        char escape = '\\';
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat updatedFormat = csvFormat.withEscape(escape);

        // Then
        assertNotSame(csvFormat, updatedFormat);
        assertEquals(escape, updatedFormat.getEscapeCharacter());
    }

    @Test
    public void testWithEscapeUsingReflection() throws Exception {
        // Given
        char escape = '\\';
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        CSVFormat csvFormatSpy = spy(csvFormat);

        // When
        CSVFormat updatedFormat = (CSVFormat) invokePrivateMethod(csvFormatSpy, "withEscape", char.class, escape);

        // Then
        assertNotSame(csvFormat, updatedFormat);
        assertEquals(escape, updatedFormat.getEscapeCharacter());
    }

    private Object invokePrivateMethod(Object object, String methodName, Class<?> parameterType, Object argument) throws Exception {
        Class<?>[] parameterTypes = { parameterType };
        Object[] arguments = { argument };
        return object.getClass().getDeclaredMethod(methodName, parameterTypes)
                .invoke(object, arguments);
    }
}
